   141→		for i, j := 0, len(parts)-1; i < j; i, j = i+1, j-1 {
   142→			parts[i], parts[j] = parts[j], parts[i]
   143→		}
   144→		nameParts[0] = strings.Join(parts, ".")
   145→	}
